function ProteinPromiseSection() {
  const left = FEATURES.slice(0, 2)
  const right = FEATURES.slice(2, 4)

  return (
    <section id="recipes" className="relative overflow-hidden">
      <div className="absolute inset-0">
        <img
          src="/st-images/stopFakeNutrition.png"
          alt="Protein chips and bars background"
          className="h-full w-full object-cover"
        />
        <div className="absolute inset-0 bg-white/50" />
        <div className="absolute inset-0 bg-black/60" />
      </div>

      <FullContainer className="relative py-12 md:py-16">
        <Container>
          <div className="mx-auto max-w-3xl text-center">
            <span className="inline-flex rounded-full border border-primary/40 bg-black px-4 py-1 text-xs font-semibold text-primary">
              Protein Innovation Studio
            </span>
            <h2 className="mt-4 font-bebas text-[45px] font-normal leading-[1.2] text-white uppercase md:text-[72px]">
              Stop fake nutrition.
              <br />
              Start real{' '}
              <span className="font-dirty-brush text-[45px] leading-[1.2] tracking-[-0.04em] text-primary md:text-[72px]">
                protein.
              </span>
            </h2>
            <p className="font-inter mt-4 max-w-2xl text-[14px] font-light leading-tight text-white md:text-[16px]">
              We turn ideas into protein products people actually crave —
              engineered for performance, crafted for taste, and built for real
              market success.
            </p>
          </div>

          <div className="relative mx-auto mt-10 flex max-w-5xl flex-col items-stretch gap-1 px-1 md:flex-row md:items-center md:gap-0 md:px-2">
            <FeaturesBlobPanel>
              {left.map((item, idx) => (
                <FeatureCell key={item.heading} item={item} showDivider={idx === 0} />
              ))}
            </FeaturesBlobPanel>
            <div className="absolute top-1/2 -translate-y-1/2 left-1/2 -translate-x-7 right-0 md:hidden z-10 shrink-0 justify-center px-1 py-1 md:-mx-7 md:px-0 md:py-0">
              <button
                type="button"
                className="pointer-events-auto flex h-[52px] w-[52px] items-center justify-center rounded-full border-[7px] border-black bg-primary md:h-[64px] md:w-[64px] md:border-8"
                aria-label="Explore protein innovation"
              >
                <ArrowUpRightIcon />
              </button>
            </div>
            <div className="relative hidden md:flex z-10 shrink-0 justify-center px-1 py-1 md:-mx-7 md:px-0 md:py-0">
              <button
                type="button"
                className="pointer-events-auto flex h-[52px] w-[52px] items-center justify-center rounded-full border-[7px] border-black bg-primary md:h-[64px] md:w-[64px] md:border-8"
                aria-label="Explore protein innovation"
              >
                <ArrowUpRightIcon />
              </button>
            </div>
            <FeaturesBlobPanel mirror>
              {right.map((item, idx) => (
                <FeatureCell key={item.heading} item={item} showDivider={idx === 0} />
              ))}
            </FeaturesBlobPanel>
          </div>
        </Container>
      </FullContainer>
    </section>
  )
}

export default ProteinPromiseSection

function FeaturesBlobPanel({ mirror = false, children }) {
  const reactId = useId()
  const clipPathId = `feature-blob-${reactId.replace(/:/g, '')}-clip`

  return (
    <div className="relative min-h-[168px] flex-1 md:min-h-[170px]">
      <div
        className={`absolute inset-0 hidden overflow-visible md:block ${mirror ? 'scale-x-[-1]' : ''}`}
        aria-hidden
      >
        <FeatureBlobSvg clipPathId={clipPathId} />
      </div>

      <div
        className={`absolute inset-0 rounded-3xl  bg-white/20 backdrop-blur-xl md:hidden ${mirror ? '' : ''}`}
        aria-hidden
      />

      <div
        className={`relative z-10 grid h-full min-h-[168px] grid-cols-2 md:min-h-[187px] ${mirror ? '' : ''}`}
      >
        {children}
      </div>
      <div className=' h-15 border-[0.5px] border-white/30 absolute left-[50%] translate-y-full top-0 translate-x-[-50%]'>
      </div>
    </div>
  )
}

function FeatureBlobSvg({ clipPathId }) {
  const clipUrl = `url(#${clipPathId})`

  return (
    <svg
      width="498"
      height="187"
      viewBox="0 0 498 187"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className="h-full w-full"
      preserveAspectRatio="none"
    >
      <defs>
        <clipPath id={clipPathId} clipPathUnits="userSpaceOnUse" transform="translate(20 20)">
          <path d={FEATURE_PANEL_PATH_D} />
        </clipPath>
      </defs>
      <foreignObject x="-20" y="-20" width="537.602" height="226.375">
        <div
          xmlns="http://www.w3.org/1999/xhtml"
          style={{
            backdropFilter: 'blur(20px)',
            WebkitBackdropFilter: 'blur(20px)',
            clipPath: clipUrl,
            height: '100%',
            width: '100%',
          }}
        />
      </foreignObject>
      <path d={FEATURE_PANEL_PATH_D} fill="white" fillOpacity="0.2" />
    </svg>
  )
}

function FeatureCell({ item, showDivider }) {
  const { Icon } = item

  return (
    <div
      className={[
        'relative flex flex-col items-center justify-center px-4 py-6 text-center md:px-6 md:py-7',
        showDivider ? '' : '',
      ].join(' ')}
    >
      <div className="mb-3 bg-black rounded-lg p-2 flex h-11 w-11 shrink-0 items-center justify-center text-primary md:h-16 md:w-16">
        <Icon />
      </div>
      <p className="font-inter text-xs lg:text-[15px] font-light leading-snug tracking-[0.01em] max-w-[150px] text-center text-[#cdd4dd]">
        {item.heading}
      </p>
    </div>
  )
}

function ArrowUpRightIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 18 18" fill="none" xmlns="http://www.w3.org/2000/svg">
      <path d="M17.9999 11.667C17.9997 12.2191 17.5521 12.667 16.9999 12.667C16.4477 12.667 16.0001 12.2191 15.9999 11.667V3.41406L1.70696 17.707C1.31643 18.0976 0.683417 18.0976 0.292893 17.707C-0.0976309 17.3165 -0.0976312 16.6835 0.292893 16.293L14.5859 2H6.33293C5.7808 1.99982 5.33293 1.55218 5.33293 1C5.33293 0.447824 5.7808 0.000175969 6.33293 0H16.9999C17.5522 0 17.9999 0.447715 17.9999 1V11.667Z" fill="black" />
    </svg>
  )
}
